INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (1, 3, "", 0.2, 129811, "drama_talk_surprise_in_shy", "", 6014, "drama_talk_surprise_loop_shy", 6, 0);
INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES ("", 21, "", "", "vo_minigame_1013", "vo_minigame_1013_top_talk_6_002", "", 6015, 0, 6, 0);
INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (0, 11, 0.3, 0, 129811, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 0, 6016, 1, 6, 9);
