INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (0, 11, 0.3, 0, 129911, "私の班のみなさんも\n変わらず訓練に励んで\nいるようですわね\n殊勝なことです", 0, 7006, 1, 7, 6);
