INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (0, 11, 0, 0, 129811, "エリコ班の急成長は\n騎士団の中でも話題に\nなってたからな\nホントすげえ奴等だよ", 0, 7011, 1, 7, 6);
