INSERT INTO `v1_2f4b5440e4df55c94ac66d11964b374f912a4cabc79282aa38e032f71830505f` VALUES (0, 11, 0.3, 0, 129811, "マコト班のみんなも、\nしっかり頑張って\nくれてるみたいだ\n教官としても嬉しいぜ", 0, 8006, 1, 8, 7);
